const r="http://127.0.0.1:8081";async function a(n,t){const e=await fetch(`${r}/returns/items`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({return_id:n,...t})});return e.ok?(await e.json()).data:null}async function o(n){try{const t=await fetch(`${r}/returns/${n}`,{cache:"no-store"});return t.ok?(await t.json()).data:null}catch{return null}}async function c(n){try{const t=await fetch(`${r}/returns?${n}`,{cache:"no-store"});return t.ok?(await t.json()).data:null}catch{return null}}export{a,c as b,o as g};
